jh1730@newton:~/dev/open/LF/tmp$ cat Main.java
public class Main {

  public static void main(String[] args) {
    for (int i=100; i<110; i++) {
      final int t=i;
      new Thread() {
      	  public void run() {System.out.println(".. thread-" + t + " ready to set count ..."); StaticTest.count("thread-"+t, t);}
      }.start();
    }

    try {Thread.sleep(60000);} catch(Exception e) {e.printStackTrace();}
  }
}
